import { Formik } from "formik";
import { Player } from "../../objects/player";
import TextField from "../../atoms/textfield/textfield";

interface AdminGameStatProps {
    players? : Player[]
}

const AdminGameStatsEdit = (adminProps : AdminGameStatProps)  =>
{   
    const initialValues = {
        gameStats: adminProps.players?.map(player => ({
          PlayerId: player.id,
          id : 0, playerId : player.id, fixture : 0, goals : 0, assists : 0, gso : 0, apps : 0, playerName: player.firstname + ' ' + player.surname, shots : 0, tackles : 0, season : 0
        })),
      };

  
    return(
        <Formik
            initialValues={initialValues}
            onSubmit={(values) => {
                alert(values.gameStats);
                //onSubmit(values.gameStats); // This is where you'd handle submitting to the API            
            }}
        >    
            {formik => (
                <div>           
                    <form onSubmit={formik.handleSubmit}>

                        {formik.values.gameStats.map((gameStat, index) => (
                            <div className="row" key={gameStat.playerId}>
                                <label>{players.find(p => p.id === gameStat.playerId)?.surname}</label>
                                <div className="col-2">
                                    <TextField label="Goals" name="goals" value="0" formik={formik}/>
                                </div>
                            </div>

                        ))}
                    
                        <div className="row">
                            <div className="col-2">                                
                                <button className="btn btn-primary" type="submit">Go</button>    
                            </div>
                        </div> 
                    </form>            
                </div>
            )}
        </Formik>
    );
}

export default AdminGameStatsEdit;




